// --- Payment Models ---

enum PaymentStatus { initial, processing, success, failure, cancelled }

class PaymentResult {
  final PaymentStatus status;
  final String? transactionId;
  final String? message;
  final String? paymentMethodType;

  PaymentResult({
    required this.status,
    this.transactionId,
    this.message,
    this.paymentMethodType,
  });

  @override
  String toString() =>
      'PaymentResult(status: $status, transactionId: $transactionId, message: $message, paymentMethodType: $paymentMethodType)';
}

class InAppProduct {
  final String id;
  final String title;
  final String description;
  final String price;
  final String currencyCode;

  InAppProduct({
    required this.id,
    required this.title,
    required this.description,
    required this.price,
    required this.currencyCode,
  });

  factory InAppProduct.fromProductDetails(ProductDetails details) {
    return InAppProduct(
      id: details.id,
      title: details.title,
      description: details.description,
      price: details.price,
      currencyCode: details.currencyCode,
    );
  }
}

// --- Payment Exceptions ---

class PaymentException implements Exception {
  final String message;
  final String? code;

  PaymentException(this.message, {this.code});

  @override
  String toString() => 'PaymentException: $message (Code: $code)';
}

