class BackendApiClient {
  static const String _baseUrl = 'YOUR_BACKEND_API_BASE_URL'; // Replace with your actual backend URL

  static Future<Map<String, dynamic>> createPaymentIntent(
      double amount, String currency, String paymentMethodId) async {
    final response = await http.post(
      Uri.parse('$_baseUrl/create-payment-intent'),
      headers: {'Content-Type': 'application/json'},
      body: json.encode({
        'amount': (amount * 100).toInt(), // Stripe expects amount in cents
        'currency': currency,
        'paymentMethodId': paymentMethodId,
      }),
    );

    if (response.statusCode == 200) {
      return json.decode(response.body);
    } else {
      throw PaymentException(
          'Failed to create PaymentIntent: ${response.body}',
          code: response.statusCode.toString());
    }
  }

  static Future<Map<String, dynamic>> verifyInAppPurchase(
      String platform, String purchaseToken, String productId) async {
    final response = await http.post(
      Uri.parse('$_baseUrl/verify-in-app-purchase'),
      headers: {'Content-Type': 'application/json'},
      body: json.encode({
        'platform': platform,
        'purchaseToken': purchaseToken,
        'productId': productId,
      }),
    );

    if (response.statusCode == 200) {
      return json.decode(response.body);
    } else {
      throw PaymentException(
          'Failed to verify in-app purchase: ${response.body}',
          code: response.statusCode.toString());
    }
  }
}

